output.sparql:
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
SELECT ?club ?clubLabel WHERE {
  wd:Q82198 p:P57 ?statement .
  ?statement ps:P57 ?club .
  ?statement pq:P580 ?startDate .
  OPTIONAL {
    ?statement pq:P585 ?endDate
  }
  FILTER(?startDate <= "2020-12-31" ^^ xsd:date &&(! BOUND(?endDate) || ?endDate >= "2020-01-01" ^^ xsd:date))
  OPTIONAL {
    ?club rdfs:label ?clubLabel .
    FILTER(lang(?clubLabel) = "en")
  }
}
